-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH non_rgstrd_data AS (
  SELECT * FROM {{ ref('int_eqpmnt_non_rgstrd_filtered') }}
),

dim_equipment_lookup AS (
  SELECT * FROM {{ ref('int_dim_equipment_lookup') }}
)

SELECT
  s.MARK_CD,
  s.EQPUN_NBR,
  s.RECORD_CREATE_TMS,

  'N' AS REGISTERED_IND,
  d.DIM_EQUIPMENT_ID AS o_DIM_EQUIPMENT_ID,
  '' AS o_MAX_DIM_EQUIPMENT_ID,
  'N' AS SRC_REGSTRD,
  IFF(d.DIM_EQUIPMENT_ID IS NULL, 'I', 'U') AS I_U_FLG,
  'N/A' AS AAR_CAR_CD_MD5

FROM non_rgstrd_data s
LEFT JOIN dim_equipment_lookup d
  ON TRIM(s.MARK_CD) = d.MARK_CD
  AND TRIM(s.EQPUN_NBR) = d.EQPUN_NBR
